// Final validation gate before publishing.
// Confirms all required content pieces are present and meet minimum quality thresholds.
// Throws on any failure to prevent bad content from reaching GitHub.
const ctx = $input.first().json;

const errors = [];

// --- summary ---
if (!ctx.summary || typeof ctx.summary !== 'object') {
  errors.push('Missing summary object');
} else {
  if (!ctx.summary.headline || ctx.summary.headline.length < 10) errors.push('summary.headline missing or too short');
  if (!ctx.summary.overview || ctx.summary.overview.length < 100) errors.push('summary.overview missing or too short');
  if (!Array.isArray(ctx.summary.key_events) || ctx.summary.key_events.length === 0) errors.push('summary.key_events empty');
  if (!['bullish', 'bearish', 'neutral', 'mixed'].includes(ctx.summary.sentiment)) errors.push('summary.sentiment invalid');
  if (typeof ctx.summary.topic_score !== 'number') errors.push('summary.topic_score missing');
  // Validate top-level sources when present
  if (Array.isArray(ctx.summary.sources)) {
    ctx.summary.sources.forEach((s, i) => {
      if (!s.source_name || String(s.source_name).trim().length === 0) {
        errors.push(`summary.sources[${i}] missing source_name`);
      }
    });
  }
  // Validate per-event sources when present
  if (Array.isArray(ctx.summary.key_events)) {
    ctx.summary.key_events.forEach((e, i) => {
      if (Array.isArray(e.sources)) {
        e.sources.forEach((s, j) => {
          if (!s.source_name || String(s.source_name).trim().length === 0) {
            errors.push(`summary.key_events[${i}].sources[${j}] missing source_name`);
          }
        });
      }
    });
  }
}

// --- article ---
if (!ctx.article_md || ctx.article_md.length < 200) {
  errors.push('article_md missing or too short (minimum 200 chars)');
} else if (!ctx.article_md.startsWith('#')) {
  errors.push('article_md does not start with a Markdown heading');
}

// --- expectation_check ---
if (!ctx.expectation_check || typeof ctx.expectation_check !== 'object') {
  errors.push('Missing expectation_check object');
} else {
  if (!Array.isArray(ctx.expectation_check.expectations_checked)) errors.push('expectation_check.expectations_checked missing');
  if (!Array.isArray(ctx.expectation_check.surprise_events)) errors.push('expectation_check.surprise_events missing');
  if (typeof ctx.expectation_check.alignment_score !== 'number') errors.push('expectation_check.alignment_score missing');
  // Validate per-expectation source when present
  if (Array.isArray(ctx.expectation_check.expectations_checked)) {
    ctx.expectation_check.expectations_checked.forEach((e, i) => {
      if (e.source !== null && e.source !== undefined) {
        if (typeof e.source !== 'object' || Array.isArray(e.source)) {
          errors.push(`expectation_check.expectations_checked[${i}].source must be an object or null`);
        } else if (!e.source.source_name || String(e.source.source_name).trim().length === 0) {
          errors.push(`expectation_check.expectations_checked[${i}].source missing source_name`);
        } else if (e.source.source_url !== null && e.source.source_url !== undefined) {
          if (typeof e.source.source_url !== 'string' || !/^https?:\/\//i.test(e.source.source_url)) {
            errors.push(`expectation_check.expectations_checked[${i}].source.source_url must be an HTTP or HTTPS URL or null`);
          }
        }
      }
    });
  }
}

// --- tomorrow_outlook ---
if (!ctx.tomorrow_outlook || typeof ctx.tomorrow_outlook !== 'object') {
  errors.push('Missing tomorrow_outlook object');
} else {
  if (!Array.isArray(ctx.tomorrow_outlook.key_watchpoints) || ctx.tomorrow_outlook.key_watchpoints.length === 0) errors.push('tomorrow_outlook.key_watchpoints empty');
  if (!ctx.tomorrow_outlook.outlook_summary || ctx.tomorrow_outlook.outlook_summary.length < 50) errors.push('tomorrow_outlook.outlook_summary missing or too short');
  if (!['low', 'medium', 'high'].includes(ctx.tomorrow_outlook.risk_level)) errors.push('tomorrow_outlook.risk_level invalid');
  // Validate per-watchpoint source when present
  if (Array.isArray(ctx.tomorrow_outlook.key_watchpoints)) {
    ctx.tomorrow_outlook.key_watchpoints.forEach((w, i) => {
      if (w.source !== null && w.source !== undefined) {
        if (typeof w.source !== 'object' || Array.isArray(w.source)) {
          errors.push(`tomorrow_outlook.key_watchpoints[${i}].source must be an object or null`);
        } else if (!w.source.source_name || String(w.source.source_name).trim().length === 0) {
          errors.push(`tomorrow_outlook.key_watchpoints[${i}].source missing source_name`);
        } else if (w.source.source_url !== null && w.source.source_url !== undefined) {
          if (typeof w.source.source_url !== 'string' || !/^https?:\/\//i.test(w.source.source_url)) {
            errors.push(`tomorrow_outlook.key_watchpoints[${i}].source.source_url must be an HTTP or HTTPS URL or null`);
          }
        }
      }
    });
  }
  // Validate per-event source when present
  if (Array.isArray(ctx.tomorrow_outlook.scheduled_events)) {
    ctx.tomorrow_outlook.scheduled_events.forEach((e, i) => {
      if (e.source !== null && e.source !== undefined) {
        if (typeof e.source !== 'object' || Array.isArray(e.source)) {
          errors.push(`tomorrow_outlook.scheduled_events[${i}].source must be an object or null`);
        } else if (!e.source.source_name || String(e.source.source_name).trim().length === 0) {
          errors.push(`tomorrow_outlook.scheduled_events[${i}].source missing source_name`);
        } else if (e.source.source_url !== null && e.source.source_url !== undefined) {
          if (typeof e.source.source_url !== 'string' || !/^https?:\/\//i.test(e.source.source_url)) {
            errors.push(`tomorrow_outlook.scheduled_events[${i}].source.source_url must be an HTTP or HTTPS URL or null`);
          }
        }
      }
    });
  }
}

// --- video_script ---
if (!ctx.video_script || typeof ctx.video_script !== 'object') {
  errors.push('Missing video_script object');
} else {
  if (!ctx.video_script.intro || ctx.video_script.intro.length < 30) errors.push('video_script.intro missing or too short');
  if (!Array.isArray(ctx.video_script.segments) || ctx.video_script.segments.length < 2) errors.push('video_script.segments missing or fewer than 2');
  if (!ctx.video_script.outro || ctx.video_script.outro.length < 30) errors.push('video_script.outro missing or too short');
  // Validate per-segment sources when present
  if (Array.isArray(ctx.video_script.segments)) {
    ctx.video_script.segments.forEach((seg, i) => {
      if (Array.isArray(seg.sources)) {
        seg.sources.forEach((s, j) => {
          if (!s.source_name || String(s.source_name).trim().length === 0) {
            errors.push(`video_script.segments[${i}].sources[${j}] missing source_name`);
          }
        });
      }
    });
  }
}

// --- youtube_metadata ---
if (!ctx.youtube_metadata || typeof ctx.youtube_metadata !== 'object') {
  errors.push('Missing youtube_metadata object');
} else {
  if (!ctx.youtube_metadata.title || ctx.youtube_metadata.title.length < 10) errors.push('youtube_metadata.title missing or too short');
  if (!ctx.youtube_metadata.description || ctx.youtube_metadata.description.length < 100) errors.push('youtube_metadata.description missing or too short');
  if (!Array.isArray(ctx.youtube_metadata.tags) || ctx.youtube_metadata.tags.length < 5) errors.push('youtube_metadata.tags missing or fewer than 5');
}

// --- image_assets (non-blocking — images step may be skipped or produce warnings) ---
// Image generation is an optional enrichment step; pipeline continues even when absent.
// Issues are recorded in imageAssetWarnings (not errors) so they never block publishing.
const imageAssetWarnings = Array.isArray(ctx.image_asset_warnings) ? [...ctx.image_asset_warnings] : [];

if (ctx.image_assets !== undefined && ctx.image_assets !== null) {
  if (typeof ctx.image_assets !== 'object') {
    imageAssetWarnings.push('image_assets must be an object when present');
  } else {
    if (!Array.isArray(ctx.image_assets.images) || ctx.image_assets.images.length === 0) {
      imageAssetWarnings.push('image_assets.images must be a non-empty array');
    }
    if (typeof ctx.image_assets.image_count !== 'number') {
      imageAssetWarnings.push('image_assets.image_count must be a number');
    }
    if (!['openai', 'google'].includes(ctx.image_assets.provider)) {
      imageAssetWarnings.push('image_assets.provider must be openai or google');
    }
  }
}

if (errors.length > 0) {
  throw new Error(`Validation failed for ${ctx.topic_slug}/${ctx.date_key} (${errors.length} error(s)):\n- ${errors.join('\n- ')}`);
}

// All checks passed — set validated flag and strip raw alerts array to reduce payload size
const { alerts, clusters, ...cleanCtx } = ctx;
return [{
  json: {
    ...cleanCtx,
    alert_count: ctx.alert_count,
    cluster_count: ctx.cluster_count,
    validated: true,
    image_asset_warnings: imageAssetWarnings.length > 0 ? imageAssetWarnings : null,
    github_commit_sha: null
  }
}];
